class InventoryLine extends DataClass implements Insertable<InventoryLine> {
  final int id;
  final int sessionId;
  final int productId;
  final String productName;
  final String? barcode;
  final int expectedQty;
  final int? countedQty;
  final int? difference;
  final int defectiveQty;
  final int obsoleteQty;
  final int expiredQty;
  final String? shopId;
  final String? terminalId;
  final bool isValidated;
  final String notes;
  const InventoryLine({
    required this.id,
    required this.sessionId,
    required this.productId,
    required this.productName,
    this.barcode,
    required this.expectedQty,
    this.countedQty,
    this.difference,
    required this.defectiveQty,
    required this.obsoleteQty,
    required this.expiredQty,
    this.shopId,
    this.terminalId,
    required this.isValidated,
    required this.notes,
  });
  @override
  Map<String, Expression> toColumns(bool nullToAbsent) {
    final map = <String, Expression>{};
    map['id'] = Variable<int>(id);
    map['session_id'] = Variable<int>(sessionId);
    map['product_id'] = Variable<int>(productId);
    map['product_name'] = Variable<String>(productName);
    if (!nullToAbsent || barcode != null) {
      map['barcode'] = Variable<String>(barcode);
    }
    map['expected_qty'] = Variable<int>(expectedQty);
    if (!nullToAbsent || countedQty != null) {
      map['counted_qty'] = Variable<int>(countedQty);
    }
    if (!nullToAbsent || difference != null) {
      map['difference'] = Variable<int>(difference);
    }
    map['defective_qty'] = Variable<int>(defectiveQty);
    map['obsolete_qty'] = Variable<int>(obsoleteQty);
    map['expired_qty'] = Variable<int>(expiredQty);
    if (!nullToAbsent || shopId != null) {
      map['shop_id'] = Variable<String>(shopId);
    }
    if (!nullToAbsent || terminalId != null) {
      map['terminal_id'] = Variable<String>(terminalId);
    }
    map['is_validated'] = Variable<bool>(isValidated);
    map['notes'] = Variable<String>(notes);
    return map;
  }

  InventoryLinesCompanion toCompanion(bool nullToAbsent) {
    return InventoryLinesCompanion(
      id: Value(id),
      sessionId: Value(sessionId),
      productId: Value(productId),
      productName: Value(productName),
      barcode: barcode == null && nullToAbsent
          ? const Value.absent()
          : Value(barcode),
      expectedQty: Value(expectedQty),
      countedQty: countedQty == null && nullToAbsent
          ? const Value.absent()
          : Value(countedQty),
      difference: difference == null && nullToAbsent
          ? const Value.absent()
          : Value(difference),
      defectiveQty: Value(defectiveQty),
      obsoleteQty: Value(obsoleteQty),
      expiredQty: Value(expiredQty),
      shopId: shopId == null && nullToAbsent
          ? const Value.absent()
          : Value(shopId),
      terminalId: terminalId == null && nullToAbsent
          ? const Value.absent()
          : Value(terminalId),
      isValidated: Value(isValidated),
      notes: Value(notes),
    );
  }

  factory InventoryLine.fromJson(
    Map<String, dynamic> json, {
    ValueSerializer? serializer,
  }) {
    serializer ??= driftRuntimeOptions.defaultSerializer;
    return InventoryLine(
      id: serializer.fromJson<int>(json['id']),
      sessionId: serializer.fromJson<int>(json['sessionId']),
      productId: serializer.fromJson<int>(json['productId']),
      productName: serializer.fromJson<String>(json['productName']),
      barcode: serializer.fromJson<String?>(json['barcode']),
      expectedQty: serializer.fromJson<int>(json['expectedQty']),
      countedQty: serializer.fromJson<int?>(json['countedQty']),
      difference: serializer.fromJson<int?>(json['difference']),
      defectiveQty: serializer.fromJson<int>(json['defectiveQty']),
      obsoleteQty: serializer.fromJson<int>(json['obsoleteQty']),
      expiredQty: serializer.fromJson<int>(json['expiredQty']),
      shopId: serializer.fromJson<String?>(json['shopId']),
      terminalId: serializer.fromJson<String?>(json['terminalId']),
      isValidated: serializer.fromJson<bool>(json['isValidated']),
      notes: serializer.fromJson<String>(json['notes']),
    );
  }
  @override
  Map<String, dynamic> toJson({ValueSerializer? serializer}) {
    serializer ??= driftRuntimeOptions.defaultSerializer;
    return <String, dynamic>{
      'id': serializer.toJson<int>(id),
      'sessionId': serializer.toJson<int>(sessionId),
      'productId': serializer.toJson<int>(productId),
      'productName': serializer.toJson<String>(productName),
      'barcode': serializer.toJson<String?>(barcode),
      'expectedQty': serializer.toJson<int>(expectedQty),
      'countedQty': serializer.toJson<int?>(countedQty),
      'difference': serializer.toJson<int?>(difference),
      'defectiveQty': serializer.toJson<int>(defectiveQty),
      'obsoleteQty': serializer.toJson<int>(obsoleteQty),
      'expiredQty': serializer.toJson<int>(expiredQty),
      'shopId': serializer.toJson<String?>(shopId),
      'terminalId': serializer.toJson<String?>(terminalId),
      'isValidated': serializer.toJson<bool>(isValidated),
      'notes': serializer.toJson<String>(notes),
