    difference: difference.present ? difference.value : this.difference,
    defectiveQty: defectiveQty ?? this.defectiveQty,
    obsoleteQty: obsoleteQty ?? this.obsoleteQty,
    expiredQty: expiredQty ?? this.expiredQty,
    shopId: shopId.present ? shopId.value : this.shopId,
    terminalId: terminalId.present ? terminalId.value : this.terminalId,
    isValidated: isValidated ?? this.isValidated,
    notes: notes ?? this.notes,
  );
  InventoryLine copyWithCompanion(InventoryLinesCompanion data) {
    return InventoryLine(
      id: data.id.present ? data.id.value : this.id,
      sessionId: data.sessionId.present ? data.sessionId.value : this.sessionId,
      productId: data.productId.present ? data.productId.value : this.productId,
