          ? data.productName.value
          : this.productName,
      barcode: data.barcode.present ? data.barcode.value : this.barcode,
      expectedQty: data.expectedQty.present
          ? data.expectedQty.value
          : this.expectedQty,
      countedQty: data.countedQty.present
          ? data.countedQty.value
