      difference: data.difference.present
          ? data.difference.value
          : this.difference,
      defectiveQty: data.defectiveQty.present
          ? data.defectiveQty.value
          : this.defectiveQty,
      obsoleteQty: data.obsoleteQty.present
          ? data.obsoleteQty.value
          : this.obsoleteQty,
      expiredQty: data.expiredQty.present
          ? data.expiredQty.value
