class Expense extends DataClass implements Insertable<Expense> {
  final int id;
  final String description;
  final double amount;
  final String category;
  final int userId;
  final String? shopId;
  final String? terminalId;
  final DateTime date;
  final String? imagePath;
  final String? remoteId;
  const Expense({
    required this.id,
    required this.description,
    required this.amount,
    required this.category,
    required this.userId,
    this.shopId,
    this.terminalId,
    required this.date,
    this.imagePath,
    this.remoteId,
  });
  @override
  Map<String, Expression> toColumns(bool nullToAbsent) {
    final map = <String, Expression>{};
    map['id'] = Variable<int>(id);
    map['description'] = Variable<String>(description);
    map['amount'] = Variable<double>(amount);
    map['category'] = Variable<String>(category);
    map['user_id'] = Variable<int>(userId);
    if (!nullToAbsent || shopId != null) {
      map['shop_id'] = Variable<String>(shopId);
    }
    if (!nullToAbsent || terminalId != null) {
      map['terminal_id'] = Variable<String>(terminalId);
    }
    map['date'] = Variable<DateTime>(date);
    if (!nullToAbsent || imagePath != null) {
      map['image_path'] = Variable<String>(imagePath);
    }
    if (!nullToAbsent || remoteId != null) {
      map['remote_id'] = Variable<String>(remoteId);
    }
    return map;
  }

  ExpensesCompanion toCompanion(bool nullToAbsent) {
    return ExpensesCompanion(
      id: Value(id),
      description: Value(description),
      amount: Value(amount),
      category: Value(category),
      userId: Value(userId),
      shopId: shopId == null && nullToAbsent
          ? const Value.absent()
          : Value(shopId),
      terminalId: terminalId == null && nullToAbsent
          ? const Value.absent()
          : Value(terminalId),
      date: Value(date),
      imagePath: imagePath == null && nullToAbsent
          ? const Value.absent()
          : Value(imagePath),
      remoteId: remoteId == null && nullToAbsent
          ? const Value.absent()
          : Value(remoteId),
    );
  }

  factory Expense.fromJson(
    Map<String, dynamic> json, {
    ValueSerializer? serializer,
  }) {
    serializer ??= driftRuntimeOptions.defaultSerializer;
    return Expense(
      id: serializer.fromJson<int>(json['id']),
      description: serializer.fromJson<String>(json['description']),
      amount: serializer.fromJson<double>(json['amount']),
      category: serializer.fromJson<String>(json['category']),
      userId: serializer.fromJson<int>(json['userId']),
      shopId: serializer.fromJson<String?>(json['shopId']),
      terminalId: serializer.fromJson<String?>(json['terminalId']),
      date: serializer.fromJson<DateTime>(json['date']),
      imagePath: serializer.fromJson<String?>(json['imagePath']),
      remoteId: serializer.fromJson<String?>(json['remoteId']),
    );
  }
  @override
  Map<String, dynamic> toJson({ValueSerializer? serializer}) {
    serializer ??= driftRuntimeOptions.defaultSerializer;
    return <String, dynamic>{
      'id': serializer.toJson<int>(id),
      'description': serializer.toJson<String>(description),
      'amount': serializer.toJson<double>(amount),
      'category': serializer.toJson<String>(category),
      'userId': serializer.toJson<int>(userId),
      'shopId': serializer.toJson<String?>(shopId),
      'terminalId': serializer.toJson<String?>(terminalId),
      'date': serializer.toJson<DateTime>(date),
      'imagePath': serializer.toJson<String?>(imagePath),
      'remoteId': serializer.toJson<String?>(remoteId),
    };
  }

  Expense copyWith({
    int? id,
    String? description,
    double? amount,
    String? category,
    int? userId,
    Value<String?> shopId = const Value.absent(),
    Value<String?> terminalId = const Value.absent(),
    DateTime? date,
    Value<String?> imagePath = const Value.absent(),
    Value<String?> remoteId = const Value.absent(),
  }) => Expense(
    id: id ?? this.id,
    description: description ?? this.description,
    amount: amount ?? this.amount,
    category: category ?? this.category,
    userId: userId ?? this.userId,
    shopId: shopId.present ? shopId.value : this.shopId,
    terminalId: terminalId.present ? terminalId.value : this.terminalId,
    date: date ?? this.date,
    imagePath: imagePath.present ? imagePath.value : this.imagePath,
    remoteId: remoteId.present ? remoteId.value : this.remoteId,
  );
  Expense copyWithCompanion(ExpensesCompanion data) {
    return Expense(
      id: data.id.present ? data.id.value : this.id,
      description: data.description.present
          ? data.description.value
          : this.description,
      amount: data.amount.present ? data.amount.value : this.amount,
      category: data.category.present ? data.category.value : this.category,
      userId: data.userId.present ? data.userId.value : this.userId,
      shopId: data.shopId.present ? data.shopId.value : this.shopId,
      terminalId: data.terminalId.present
          ? data.terminalId.value
          : this.terminalId,
      date: data.date.present ? data.date.value : this.date,
      imagePath: data.imagePath.present ? data.imagePath.value : this.imagePath,
      remoteId: data.remoteId.present ? data.remoteId.value : this.remoteId,
    );
  }

  @override
  String toString() {
    return (StringBuffer('Expense(')
          ..write('id: $id, ')
          ..write('description: $description, ')
          ..write('amount: $amount, ')
          ..write('category: $category, ')
          ..write('userId: $userId, ')
          ..write('shopId: $shopId, ')
          ..write('terminalId: $terminalId, ')
          ..write('date: $date, ')
          ..write('imagePath: $imagePath, ')
          ..write('remoteId: $remoteId')
          ..write(')'))
        .toString();
  }

  @override
  int get hashCode => Object.hash(
    id,
    description,
    amount,
    category,
    userId,
    shopId,
    terminalId,
    date,
    imagePath,
    remoteId,
  );
  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      (other is Expense &&
          other.id == this.id &&
          other.description == this.description &&
          other.amount == this.amount &&
          other.category == this.category &&
          other.userId == this.userId &&
          other.shopId == this.shopId &&
          other.terminalId == this.terminalId &&
          other.date == this.date &&
          other.imagePath == this.imagePath &&
          other.remoteId == this.remoteId);
}

