  final int productId;
  final String name;
  final String? barcode;
  final double priceModifier;
  final int stockQty;
  final bool isActive;
  const ProductVariant({
    required this.id,
    required this.productId,
    required this.name,
    this.barcode,
    required this.priceModifier,
    required this.stockQty,
    required this.isActive,
  });
  @override
  Map<String, Expression> toColumns(bool nullToAbsent) {
    final map = <String, Expression>{};
    map['id'] = Variable<int>(id);
    map['product_id'] = Variable<int>(productId);
    map['name'] = Variable<String>(name);
    if (!nullToAbsent || barcode != null) {
      map['barcode'] = Variable<String>(barcode);
    }
    map['price_modifier'] = Variable<double>(priceModifier);
    map['stock_qty'] = Variable<int>(stockQty);
    map['is_active'] = Variable<bool>(isActive);
    return map;
  }

  ProductVariantsCompanion toCompanion(bool nullToAbsent) {
    return ProductVariantsCompanion(
      id: Value(id),
      productId: Value(productId),
      name: Value(name),
      barcode: barcode == null && nullToAbsent
          ? const Value.absent()
          : Value(barcode),
      priceModifier: Value(priceModifier),
      stockQty: Value(stockQty),
      isActive: Value(isActive),
    );
  }

  factory ProductVariant.fromJson(
    Map<String, dynamic> json, {
    ValueSerializer? serializer,
  }) {
    serializer ??= driftRuntimeOptions.defaultSerializer;
    return ProductVariant(
      id: serializer.fromJson<int>(json['id']),
      productId: serializer.fromJson<int>(json['productId']),
      name: serializer.fromJson<String>(json['name']),
      barcode: serializer.fromJson<String?>(json['barcode']),
      priceModifier: serializer.fromJson<double>(json['priceModifier']),
      stockQty: serializer.fromJson<int>(json['stockQty']),
      isActive: serializer.fromJson<bool>(json['isActive']),
    );
  }
  @override
  Map<String, dynamic> toJson({ValueSerializer? serializer}) {
    serializer ??= driftRuntimeOptions.defaultSerializer;
    return <String, dynamic>{
      'id': serializer.toJson<int>(id),
      'productId': serializer.toJson<int>(productId),
      'name': serializer.toJson<String>(name),
      'barcode': serializer.toJson<String?>(barcode),
      'priceModifier': serializer.toJson<double>(priceModifier),
      'stockQty': serializer.toJson<int>(stockQty),
      'isActive': serializer.toJson<bool>(isActive),
    };
  }

  ProductVariant copyWith({
    int? id,
    int? productId,
    String? name,
    Value<String?> barcode = const Value.absent(),
    double? priceModifier,
    int? stockQty,
    bool? isActive,
  }) => ProductVariant(
    id: id ?? this.id,
    productId: productId ?? this.productId,
    name: name ?? this.name,
    barcode: barcode.present ? barcode.value : this.barcode,
    priceModifier: priceModifier ?? this.priceModifier,
    stockQty: stockQty ?? this.stockQty,
    isActive: isActive ?? this.isActive,
  );
  ProductVariant copyWithCompanion(ProductVariantsCompanion data) {
    return ProductVariant(
      id: data.id.present ? data.id.value : this.id,
      productId: data.productId.present ? data.productId.value : this.productId,
      name: data.name.present ? data.name.value : this.name,
      barcode: data.barcode.present ? data.barcode.value : this.barcode,
      priceModifier: data.priceModifier.present
          ? data.priceModifier.value
          : this.priceModifier,
      stockQty: data.stockQty.present ? data.stockQty.value : this.stockQty,
      isActive: data.isActive.present ? data.isActive.value : this.isActive,
    );
  }

  @override
  String toString() {
    return (StringBuffer('ProductVariant(')
          ..write('id: $id, ')
          ..write('productId: $productId, ')
          ..write('name: $name, ')
          ..write('barcode: $barcode, ')
          ..write('priceModifier: $priceModifier, ')
          ..write('stockQty: $stockQty, ')
          ..write('isActive: $isActive')
          ..write(')'))
        .toString();
  }

  @override
  int get hashCode => Object.hash(
    id,
    productId,
    name,
    barcode,
    priceModifier,
    stockQty,
    isActive,
  );
  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      (other is ProductVariant &&
          other.id == this.id &&
          other.productId == this.productId &&
          other.name == this.name &&
          other.barcode == this.barcode &&
          other.priceModifier == this.priceModifier &&
          other.stockQty == this.stockQty &&
          other.isActive == this.isActive);
}

